# Module providing geometric shapes and calculations

@abstract
class Shape:
    name: str

    def __init__(self, name: str):
        self.name = name

    @abstract
    def area(self) -> float:
        ...

    @abstract
    def perimeter(self) -> float:
        ...

    def describe(self) -> str:
        return f"Shape: {self.name}"

interface IMeasurable:
    def volume(self) -> float:
        ...

    def surface_area(self) -> float:
        ...

struct Point2D:
    x: float
    y: float

enum ShapeType:
    RECTANGLE = 0
    CIRCLE = 1
    TRIANGLE = 2
    CUBE = 3

