# Module with concrete shape implementations
from geometry import Shape, IMeasurable, ShapeType, Point2D

class Rectangle(Shape):
    width: float
    height: float
    shape_type: ShapeType

    def __init__(self, w: float, h: float):
        super().__init__("Rectangle")
        self.width = w
        self.height = h
        self.shape_type = ShapeType.RECTANGLE

    def area(self) -> float:
        return self.width * self.height

    def perimeter(self) -> float:
        return 2.0 * (self.width + self.height)

class Circle(Shape):
    radius: float
    PI: float

    def __init__(self, r: float):
        super().__init__("Circle")
        self.radius = r
        self.PI = 3.14159

    def area(self) -> float:
        return self.PI * self.radius * self.radius

    def perimeter(self) -> float:
        return 2.0 * self.PI * self.radius

class Cube(Shape, IMeasurable):
    side: float

    def __init__(self, s: float):
        super().__init__("Cube")
        self.side = s

    def area(self) -> float:
        return self.side * self.side

    def perimeter(self) -> float:
        return 4.0 * self.side

    def volume(self) -> float:
        return self.side * self.side * self.side

    def surface_area(self) -> float:
        return 6.0 * self.side * self.side

