# Module with utility functions for shape calculations
from geometry import Shape, Point2D
from concrete_shapes import Rectangle, Circle

def calculate_total_area(shapes: list[Shape]) -> float:
    total: float = 0.0
    for shape in shapes:
        total += shape.area()
    return total

def calculate_total_perimeter(shapes: list[Shape]) -> float:
    total: float = 0.0
    for shape in shapes:
        total += shape.perimeter()
    return total

def create_unit_square() -> Rectangle:
    return Rectangle(1.0, 1.0)

def distance_between_points(p1: Point2D, p2: Point2D) -> float:
    dx: float = p2.x - p1.x
    dy: float = p2.y - p1.y
    return (dx * dx + dy * dy) ** 0.5
